        super(CrossMamba, self).__init__()
        self.cross_mamba = Mamba(dim,bimamba_type="v3") # 使用v3版本,会使用额外的输入extra_emb进行特殊处理
        self.norm1 = LayerNorm(dim,'with_bias')
